import sys
input = sys.stdin.readline

def solve():
    n, m, q = map(int, input().split())
    grid = [[True]*m for _ in range(n)]  # True = free
    dp_r = [[0]*m for _ in range(n)]
    dp_d = [[0]*m for _ in range(n)]

    total = n * m  # single cells
    for r in range(n):
        for c in range(m):
            if c > 0:
                dp_r[r][c] = dp_d[r][c-1] + 1
            if r > 0:
                dp_d[r][c] = dp_r[r-1][c] + 1
            total += dp_r[r][c] + dp_d[r][c]

    results = []
    for _ in range(q):
        x, y = map(int, input().split())
        r, c = x-1, y-1
        grid[r][c] = not grid[r][c]
        if grid[r][c]:
            total += 1
        else:
            total -= 1

        # Recompute dp for (r,c) and all cells diagonally down-right
        cr, cc = r, c
        while cr < n and cc < m:
            for dc in range(2):
                nr, nc = cr + dc, cc + (1 - dc)
                if 0 <= nr < n and 0 <= nc < m:
                    old = dp_r[nr][nc] + dp_d[nr][nc]
                    if not grid[nr][nc]:
                        dp_r[nr][nc] = 0
                        dp_d[nr][nc] = 0
                    else:
                        dp_r[nr][nc] = (dp_d[nr][nc-1] + 1) if nc > 0 and grid[nr][nc-1] else 0
                        dp_d[nr][nc] = (dp_r[nr-1][nc] + 1) if nr > 0 and grid[nr-1][nc] else 0
                    total += dp_r[nr][nc] + dp_d[nr][nc] - old
            cr += 1
            cc += 1

        results.append(total)

    print('\n'.join(map(str, results)))

solve()

